def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        if ratio == 1:
            priorities[i] = 0
            continue
        score = 0.0
        for j in range(1, 21):
            if j % 3 == 0:
                term = ((-1) ** j) * (ratio ** j) / (j ** 1.5)
            elif j % 2 == 0:
                term = ((-1) ** (j+1)) * (ratio ** j) / (j * 2)
            else:
                term = ((-1) ** (j)) * (ratio ** j) / j
            score += term
        if capacity < item * 1.2:
            score *= 3.0
        elif capacity < item * 1.5:
            score *= 2.0
        elif capacity < item * 2:
            score *= 1.5
        elif capacity < item * 3:
            score *= 1.1
        penalty = 0.0
        window_size = 4
        for k in range(max(0, i - window_size), min(n, i + window_size + 1)):
            if bins[k] != 0 and k != i:
                overlap_ratio = item / bins[k]
                if 0 < overlap_ratio < 1:
                    dist = abs(k - i)
                    penalty += ((1 - overlap_ratio) ** 2) / (dist + 1)
        penalty /= (2 * window_size + 1)
        adjustment = 1 + sum([(0.05 * sin) for sin in np.sin(np.linspace(0, np.pi, 10))])
        final_score = max(0, (-score * adjustment) + penalty)
        if final_score > 10:
            final_score = 10 + (final_score - 10) ** 0.5
        priorities[i] = final_score
    return priorities
